The issue is reproducible using the sample provided by the author.

## Steps to reproduce
- Execute `flutter run` on the code sample 
- Type any word that contains "ali" or 
- Uncomment ` // _editingcontroller.text = "dghali";`
- Execute `flutter run` on the sample

<details>
<summary>code sample</summary>

```dart
import 'package:flutter/gestures.dart';
import 'package:flutter/material.dart';

void main(List<String> args) {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: TexspanTap(),
    );
  }
}

class TexspanTap extends StatefulWidget {
  @override
  _TexspanTapState createState() => _TexspanTapState();
}

class _TexspanTapState extends State<TexspanTap> {
  final TextEditingController _editingcontroller = MyTextEditingcontroller();

  @override
  void initState() {
    // _editingcontroller.text = "dghali";
    super.initState();
  }

  @override
  void dispose() {
    _editingcontroller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(),
      body: SafeArea(
        child: SingleChildScrollView(
          child: Column(
            children: [
              TextField(
                controller: _editingcontroller,
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class MyTextEditingcontroller extends TextEditingController {
  @override
  TextSpan buildTextSpan(
      {required BuildContext context,
      TextStyle? style,
      required bool withComposing}) {
    // If the composing range is out of range for the current text, ignore it to
    // preserve the tree integrity, otherwise in release mode a RangeError will
    // be thrown and this EditableText will be built with a broken subtree.

    print("text length: ${text.length}\t\t$text");
    if (text.toLowerCase().contains("ali")) {
      final List<InlineSpan> spans = [];

      final int indexOfAli = text.toLowerCase().indexOf("ali");

      print("aliIndex: $indexOfAli");

      spans.add(TextSpan(text: text.substring(0, indexOfAli)));

      spans.add(
        TextSpan(
          text: text.substring(indexOfAli, indexOfAli + 3),
          style: const TextStyle(color: Colors.red),
          recognizer: TapGestureRecognizer()
            ..onTapDown = (_) {
              ScaffoldMessenger.of(context).showSnackBar(
                const SnackBar(
                  content: Text('pressed Ali'),
                ),
              );
            },
        ),
      );

      spans.add(TextSpan(text: text.substring(indexOfAli + 3, text.length)));

      return TextSpan(style: style, children: spans);
    }

    return TextSpan(text: text, style: style);
  }
}

```
