Here is a reproduction of the bug, partial thanks to @shAdow-XJY  (https://github.com/flutter/flutter/issues/127091)

Just uncomment the line with the bug in initState to see the issue.

Workaround: There's also a line in initState to uncomment showing a workaround.

```
import 'package:flutter/gestures.dart';
import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'text_field',
      theme: ThemeData(brightness: Brightness.dark),
      home: const MyHomePage(),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({Key? key}) : super(key: key);

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  final controller = ClickController();

  @override
  void initState() {
    super.initState();

    // uncomment for bug
    // controller.text = 'Ai';

    // uncomment for workaround fix
    // Future.microtask(() => controller.text = 'Ai');
  }

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: () => FocusScope.of(context).unfocus(),
      child: Scaffold(
        appBar: AppBar(
          title: const Text('click_text_field'),
        ),
        body: Padding(
          padding: const EdgeInsets.all(8.0),
          child: SingleChildScrollView(
            child: Column(
              children: [
                TextField(
                  maxLines: null,
                  controller: controller,
                )
              ],
            ),
          ),
        ),
      ),
    );
  }
}

class ClickController extends TextEditingController {
  ClickController();

  @override
  TextSpan buildTextSpan(
      {required BuildContext context,
      TextStyle? style,
      required bool withComposing}) {
    var spans = <InlineSpan>[];

    int startIndex = 0;

    for (var i = 0; i < text.length; ++i) {
      if (text[i] == 'A') {
        spans.add(
          TextSpan(
            text: text.substring(startIndex, i),
            mouseCursor: SystemMouseCursors.click,
            recognizer: TapGestureRecognizer()
              ..onTap = () => debugPrint('click A'),
          ),
        );
        spans.add(
          TextSpan(
            text: 'A',
            mouseCursor: SystemMouseCursors.click,
            recognizer: TapGestureRecognizer()
              ..onTap = () => debugPrint('click A'),
          ),
        );
        startIndex = i + 1;
      }
    }
    if (startIndex < text.length) {
      spans.add(
        TextSpan(
          text: text.substring(startIndex, text.length),
          mouseCursor: SystemMouseCursors.text,
        ),
      );
    }

    return TextSpan(
      children: spans,
      mouseCursor: SystemMouseCursors.text,
    );
  }
}

```

